CREATE TABLE app.premium_payment_transaction (
    agency_tracking_id character varying(21) NOT NULL,
    created_at timestamp without time zone,
    submitted_at timestamp without time zone,
    completed_at timestamp without time zone,
    beneficiary_key bigint NOT NULL,
    payment_method_code app.type_payment_method_code NOT NULL,
    tracking_id text,
    premium_amount_usd numeric(38,2) NOT NULL,
    completion_status_code app.type_premium_payment_completion_status_code
);
ALTER TABLE app.premium_payment_transaction OWNER TO bedap_workflow;


CREATE FUNCTION app.insert_premium_payment_transaction(_beneficiary_key bigint, _payment_method text, _premium_amount numeric) RETURNS SETOF app.premium_payment_transaction
    LANGUAGE plpgsql
    AS $$
    DECLARE
        _current_utc TIMESTAMP WITH TIME ZONE;
        _current_julian_date VARCHAR(5);
        _max_agency_tracking_id_julian_date VARCHAR(5);
        _agency_tracking_id VARCHAR(21);
        _premium_payment_sequence BIGINT;
        _transaction_type VARCHAR(4);
        _sequence TEXT;
    BEGIN
        --set _current_utc
        _current_utc = NOW() AT TIME ZONE 'UTC';
        _current_julian_date = TO_CHAR(_current_utc, 'YYDDD');

        SELECT SUBSTRING(agency_tracking_id, 5, 5)
        FROM app.premium_payment_transaction
        ORDER BY created_at DESC
        LIMIT 1 INTO _max_agency_tracking_id_julian_date;

        IF _max_agency_tracking_id_julian_date <> _current_julian_date THEN
            ALTER SEQUENCE app.sq_premium_payment_achm RESTART;
            ALTER SEQUENCE app.sq_premium_payment_ccrd RESTART;
        END IF;
        --ACH transaction
        IF _payment_method = 'ACH' THEN
            --set transaction_type and sequence
            _transaction_type = 'ACHM';
            _sequence = 'app.sq_premium_payment_achm';
        -- CC and HSA transaction
        ELSIF _payment_method = 'CC' OR _payment_method = 'HSA' THEN
            --set transaction_type and sequence
            _transaction_type := 'CCRD';
            _sequence = 'app.sq_premium_payment_ccrd';
        ELSE
            RAISE EXCEPTION 'Payment method must be ACH, CC or HSA';
        END IF;

        --set agency_tracking_id
        _premium_payment_sequence = NEXTVAL(_sequence::REGCLASS);

        --skipping to 1 if next sequence is 0
        IF right(_premium_payment_sequence::TEXT, 1) = '0' THEN
            _premium_payment_sequence = NEXTVAL(_sequence::REGCLASS);
        END IF;

        _agency_tracking_id := _transaction_type || _current_julian_date || '01' ||
            LPAD(LEFT(_premium_payment_sequence::TEXT, 1), 4, '0') ||
            RIGHT(_premium_payment_sequence::TEXT, 6);

        INSERT INTO app.premium_payment_transaction (
            agency_tracking_id
            , created_at
            , beneficiary_key
            , payment_method_code
            , premium_amount_usd
            )
        VALUES (
            _agency_tracking_id
            , _current_utc
            , _beneficiary_key
            , _payment_method::app.type_payment_method_code
            , _premium_amount);

        RETURN QUERY
            SELECT agency_tracking_id,
            created_at,
            submitted_at,
            completed_at,
            beneficiary_key,
            payment_method_code,
            tracking_id,
            premium_amount_usd,
            completion_status_code
            FROM app.premium_payment_transaction
            WHERE agency_tracking_id = _agency_tracking_id;

        EXCEPTION WHEN UNIQUE_VIOLATION THEN
            RAISE EXCEPTION 'Error creating transaction record. Please try again.';

    END
$$;
ALTER FUNCTION app.insert_premium_payment_transaction(_beneficiary_key bigint, _payment_method text, _premium_amount numeric) OWNER TO bedap_workflow;


CREATE PROCEDURE staging.fix_persistence_safely()
    LANGUAGE plpgsql
    AS $$
DECLARE
    part record;
BEGIN
    FOR part IN
        SELECT n.nspname as schema_name, c.relname as table_name
        FROM pg_class c
        JOIN pg_namespace n ON n.oid = c.relnamespace
        WHERE c.relname LIKE '%refresh%'
        AND c.relpersistence = 'u'  -- Only 'Unlogged' items
        AND c.relkind = 'r'       -- Tables only
        order by 1, 2
    LOOP
        -- Run the alter
        EXECUTE format('ALTER TABLE %I.%I SET LOGGED', part.schema_name, part.table_name);

        -- Print progress
        RAISE NOTICE 'Committed persistence for: %.%', part.schema_name, part.table_name;

        -- CRITICAL: Save progress immediately
        COMMIT;
    END LOOP;
END;
$$;
ALTER PROCEDURE staging.fix_persistence_safely() OWNER TO bedap_workflow;


