    encode(public.digest((((((((((((((COALESCE((beneficiary_key)::character varying, ''::character varying))::text || (COALESCE((enrollment_sk)::character varying, ''::character varying))::text) || (COALESCE((enrollment_date)::character varying, ''::character varying))::text) || (COALESCE((contract_id)::character varying, ''::character varying))::text) || (COALESCE((plan_id)::character varying, ''::character varying))::text) || (COALESCE((start_date)::character varying, ''::character varying))::text) || (COALESCE((end_date)::character varying, ''::character varying))::text) || (COALESCE((group_number)::character varying, ''::character varying))::text) || (COALESCE((bin_number)::character varying, ''::character varying))::text) || (COALESCE((member_number)::character varying, ''::character varying))::text) || (COALESCE((pcn_number)::character varying, ''::character varying))::text) || (COALESCE((contract_year)::character varying, ''::character varying))::text) || (COALESCE((plan_name)::character varying, ''::character varying))::text), 'sha256'::text), 'hex'::text) AS row_sha256
   FROM app.beneficiary_prescription_card_data;


ALTER VIEW data_comparison.beneficiary_prescription_card OWNER TO bedap_workflow;


